import http from 'k6/http';
import { check, group, sleep } from 'k6';
import { Rate, Trend } from 'k6/metrics';
import { loginAndGetToken } from '../../tests/k6/helpers/auth.js';

const errorRate = new Rate('errors');
const batchDuration = new Trend('batch_duration');

const BASE_URL = __ENV.BASE_URL || 'https://quickpizza.grafana.com';

// Varied batch sizes for realistic load patterns
const BATCH_SIZES = [1, 5, 10, 25, 50];

function makeBatchPayload(size) {
  const requests = [];
  for (let i = 0; i < size; i++) {
    requests.push({});
  }
  return { requests: requests };
}

export const options = {
  scenarios: {
    smoke: {
      executor: 'per-vu-iterations',
      vus: 1,
      iterations: 5,
      maxDuration: '30s',
      exec: 'smokeTest',
      startTime: '0s',
    },
    load_test: {
      executor: 'constant-arrival-rate',
      rate: 10,
      timeUnit: '1s',
      duration: '2m',
      preAllocatedVUs: 20,
      maxVUs: 50,
      exec: 'default',
      startTime: '35s',
      gracefulStop: '30s',
    },
    baseline_regression: {
      executor: 'constant-vus',
      vus: 5,
      duration: '30s',
      exec: 'baselineTest',
      startTime: '3m10s',
    },
  },
  thresholds: {
    http_req_failed: ['rate<0.01'],
    http_req_duration: ['p(95)<5000'],
    'http_req_duration{endpoint:/api/pizza/batch}': ['p(95)<5000'],
    'http_req_duration{endpoint:/api/ratings}': ['p(95)<2000'],
    errors: ['rate<0.05'],
  },
};

export function setup() {
  const token = loginAndGetToken();
  // Verify batch endpoint exists with a single request
  const res = http.post(`${BASE_URL}/api/pizza/batch`, JSON.stringify(makeBatchPayload(1)), {
    headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
  });
  if (res.status !== 200) {
    console.warn(`Batch endpoint returned ${res.status}: ${res.body}`);
  }
  return { token: token };
}

export function smokeTest(data) {
  group('Smoke: Batch Recommendation', function () {
    const payload = makeBatchPayload(3);
    const res = http.post(`${BASE_URL}/api/pizza/batch`, JSON.stringify(payload), {
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${data.token}` },
      tags: { endpoint: '/api/pizza/batch', type: 'write', scenario: 'smoke' },
    });
    check(res, {
      'status is 200': (r) => r.status === 200,
      'response time < 5s': (r) => r.timings.duration < 5000,
      'valid JSON': (r) => {
        try { JSON.parse(r.body); return true; } catch { return false; }
      },
      'has results array': (r) => {
        try { return Array.isArray(JSON.parse(r.body).results); } catch { return false; }
      },
      'total matches request count': (r) => {
        try { return JSON.parse(r.body).total === 3; } catch { return false; }
      },
    });
  });
}

export default function (data) {
  group('Batch Recommendation — varied payload sizes', function () {
    const size = BATCH_SIZES[Math.floor(Math.random() * BATCH_SIZES.length)];
    const payload = makeBatchPayload(size);

    const res = http.post(`${BASE_URL}/api/pizza/batch`, JSON.stringify(payload), {
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${data.token}` },
      tags: { endpoint: '/api/pizza/batch', type: 'write', scenario: 'load_test' },
    });

    const success = check(res, {
      'status is 200': (r) => r.status === 200,
      'response time < 5s': (r) => r.timings.duration < 5000,
      'valid JSON': (r) => {
        try { JSON.parse(r.body); return true; } catch { return false; }
      },
      'results count matches request': (r) => {
        try { return JSON.parse(r.body).total === size; } catch { return false; }
      },
    });

    errorRate.add(!success);
    batchDuration.add(res.timings.duration);
  });
}

export function baselineTest(data) {
  group('Baseline Regression', function () {
    const ratingsRes = http.get(`${BASE_URL}/api/ratings`, {
      headers: { 'Authorization': `Bearer ${data.token}` },
      tags: { endpoint: '/api/ratings', scenario: 'baseline' },
    });
    check(ratingsRes, {
      'ratings 200': (r) => r.status === 200,
      'has ratings': (r) => {
        try { return JSON.parse(r.body).ratings !== undefined; } catch { return false; }
      },
    });

    const pizzaRes = http.post(`${BASE_URL}/api/pizza`, JSON.stringify({}), {
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${data.token}` },
      tags: { endpoint: '/api/pizza', scenario: 'baseline' },
    });
    check(pizzaRes, {
      'pizza 200': (r) => r.status === 200,
    });
  });
  sleep(0.5);
}

export function handleSummary(data) {
  return {
    stdout: JSON.stringify(data, null, 2),
    'summary.json': JSON.stringify(data),
  };
}
